-- ── Work Orders ──────────────────────────────────────────────
-- inspection_type IDs come from the migration seed — look up by name
INSERT INTO work_orders (
  id, wo_number, building_id, apartment_unit,
  inspection_type_id, requested_by, assigned_to,
  inspection_date, due_date, priority, status, notes,
  dispatched_at, completed_at, created_at
)
SELECT
  id, wo_number, building_id, apartment_unit,
  (SELECT id FROM inspection_types WHERE name = insp_type),
  requested_by, NULL,
  inspection_date::date, due_date::date, priority::work_order_priority,
  status::work_order_status, notes,
  dispatched_at, completed_at, created_at
